import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';

interface KPI {
  label: string;
  value: string | number;
  change?: string;
}

export function KpiCards({ kpis }: { kpis: KPI[] }) {
  return (
    <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
      {kpis.map((kpi) => (
        <Card key={kpi.label}>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-gray-500">
              {kpi.label}
            </CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-2xl font-bold">{kpi.value}</p>
            {kpi.change && (
              <p className="text-xs text-green-600 mt-1">{kpi.change}</p>
            )}
          </CardContent>
        </Card>
      ))}
    </div>
  );
}

import { createClient } from '@/lib/supabase/server';
import { redirect } from 'next/navigation';
import { KpiCards } from '@/components/kpi-cards';

export default async function AnalyticsPage() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) redirect('/login');

  const { data: merchant } = await supabase
    .from('merchants')
    .select('id')
    .eq('user_id', user.id)
    .single();

  if (!merchant) redirect('/login');

  const { data: kpiData } = await supabase
    .from('merchant_kpis')
    .select('*')
    .eq('merchant_id', merchant.id)
    .single();

  const kpis = [
    { label: 'Total Clients', value: kpiData?.total_clients ?? 0 },
    { label: 'Active Clients (30d)', value: kpiData?.active_clients_30d ?? 0 },
    { label: 'Transactions (7d)', value: kpiData?.transactions_7d ?? 0 },
    { label: 'Campaigns Sent', value: kpiData?.campaigns_sent ?? 0 },
  ];

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">Analytics</h1>
      <KpiCards kpis={kpis} />
    </div>
  );
}
